### Java Code:

```java
import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.*;
import java.net.URL;

public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/path/to/image.jpg"; // Replace with your URL
        String outputFilePath = "filtered_image.jpg";

        try {
            // Download the image
            BufferedImage image = downloadImageFromUrl(imageUrl);
            if (image == null) {
                System.out.println("Failed to download image.");
                return;
            }

            // Apply grayscale filter
            BufferedImage filteredImage = applyGrayscaleFilter(image);

            // Save the filtered image
            saveImageToFile(filteredImage, outputFilePath);

            System.out.println("Image downloaded and filtered successfully.");
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static BufferedImage downloadImageFromUrl(String url) throws IOException {
        URL imageUrl = new URL(url);
        BufferedImage image = ImageIO.read(imageUrl.openStream());
        return image;
    }

    private static BufferedImage applyGrayscaleFilter(BufferedImage image) {
        BufferedImage filteredImage = image.copyAll(image);

        int width = image.getWidth();
        int height = image.getHeight();

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int rgb = image.getRGB(x, y);
                int r = (rgb >> 16) & 0xFF;
                int g = (rgb >> 8) & 0xFF;
                int b = rgb & 0xFF;

                int gray = (r + g + b) / 3;
                filteredImage.setRGB(x, y, (gray << 16) | (gray << 8) | gray);
            }
        }

        return filteredImage;
    }

    private static void saveImageToFile(BufferedImage image, String filePath) throws IOException {
        ImageIO.write(image, "jpg", new File(filePath));
    }
}
```

### Explanation:
- **`downloadImageFromUrl`**: Fetches the image from the given URL using `ImageIO.read`.
- **`applyGrayscaleFilter`**: Converts the image to grayscale by averaging the RGB values of each pixel.
- **`saveImageToFile`**: Saves the filtered image to a specified file path.

### Notes:
