# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs for two locations, computes the distance in kilometers or miles, and includes error handling and documentation.

---

## Script: `haversine_distance.pl`

```perl
use strict;
use warnings;
use Getopt::Long;
use JSON;
use URI::Escape;

# Constants
my $KILOMETERS = 1;
my $MILES = 1;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    # Convert degrees to radians
    my $lat1_rad = radians($lat1);
    my $lon1_rad = radians($lon1);
    my $lat2_rad = radians($lat2);
    my $lon2_rad = radians($lon2);

    # Haversine formula
    my $a = (
        sin($lat1_rad - $lat2_rad) ** 2 +
        cos($lat1_rad) * cos($lat2_rad) * sin($lat1_rad - $lat2_rad) ** 2
    );
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radians {
    return ( $_[0] * pi() ) / 180;
}

# Example locations
my %locations = (
    'Location 1' => {
        lat => 51.5074,  # Latitude of London
        lon => -0.1278,  # Longitude of London
    },
    'Location 2' => {
        lat => 40.7128,  # Latitude of New York
        lon => -74.0060, # Longitude of New York
    },
);

# Main script
sub main {
    my ($lat1, $lon1, $lat2, $lon2, $unit) = @_;

    # Validate input
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Please provide latitude and longitude for both locations.\n";
    }

    # Check if unit is valid
    if ($unit !~ /^k$/ && $unit !~ /^m$/ && $unit !~ /^mi$/ && $unit !~ /^miles$/) {
        die "Invalid unit: $unit. Use 'k' for kilometers or 'm' for miles.\n";
    }

    # Calculate distance
    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);
    my $unit_symbol = $unit eq 'k' ? 'km' : 'mi';

    # Output result
    print "Distance between $locations{'Location 1'}->{name} and $locations{'Location 2'}->{name} is $distance $unit_symbol.\n";
}

