```swift
// BinarySearchTree.swift
import Foundation

// Define the Node structure for the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children: find the in-order successor
                let successor = findMinNode(node!.right)!
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node!
    }

    // Find the minimum value in the BST
    private func findMinNode(_ node: Node?) -> Node? {
        var current = node
        while current?.left != nil {
            current = current!.left
        }
        return current
    }

    // Traversal functions
    // Pre-order traversal: visit root, then left, then right
    func preOrderTraversal() {
        preOrderTraverse(root)
    }

    // In-order traversal: visit left, then root, then right
    func inOrderTraversal() {
        inOrderTraverse(root)
    }

    // Post-order traversal: visit left, then right, then root
    func postOrderTraversal() {
        postOrderTraverse(root)
    }

    // Helper functions for traversal
    private func preOrderTraverse(_ node: Node?) {
        if let node = node {
            print("Visit: $node.value")
            preOrderTraverse(node.left)
            preOrderTraverse(node.right)
        }
    }

    private func inOrderTraverse(_ node: Node?) {
        if let node = node {
            inOrderTraverse(node.left)
            print("Visit: $node.value")
            inOrderTraverse(node.right)
        }
    }

    private func postOrderTraverse(_ node: Node?) {
        if let node = node {
            postOrderTraverse(node.left)
            postOrderTraverse(node.right)
            print("Visit: $node.value")
        }
    }
}
```

### Explanation of the Code:

- **Node Structure**: Each node contains a value and pointers to its left and right children.
- **Insert Function**: Adds a new node to the BST by comparing the value with the current node and moving left or right accordingly.
- **Delete Function**: Removes a node from the BST while maintaining the BST properties. If a node has only one child, it is removed; if it has two children, the in-order successor is used to replace it.
- **Traversal Functions**: 
  - **Pre-order**: Visit root, then left, then right.
  - **In-order**: Visit left, then root, then right.
  - **Post-order**: Visit left, then right, then root.

This implementation is efficient with time complexity of **O(log n)** for insert and delete operations in a balanced tree, and **O(n)** in the worst case (for skewed trees). The code is clean, well-documented, and follows standard BST principles.

